using benchmark_clock = std::chrono::steady_clock;

constexpr size_t STATIC_CHUNK_SIZE = 4096;
constexpr int BENCH_BLOCK_THREADS = 256;

template <typename T>
__global__ void zero_kernel(T* data, size_t n) {
  size_t idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx < n) data[idx] = (T)0;
}

template <typename T, unsigned int compute_iterations>
__device__ __forceinline__ T bench_elem(const T x, const T f[8]) {
  T t0 = x, t1 = x, t2 = x, t3 = x, t4 = x, t5 = x, t6 = x, t7 = x;

#pragma unroll
  for (unsigned int j = 0; j < compute_iterations / 8; j++) {
    t0 = t0 * t0 + f[0];
    t1 = t1 * t1 + f[1];
    t2 = t2 * t2 + f[2];
    t3 = t3 * t3 + f[3];
    t4 = t4 * t4 + f[4];
    t5 = t5 * t5 + f[5];
    t6 = t6 * t6 + f[6];
    t7 = t7 * t7 + f[7];
  }

  if (compute_iterations % 8 > 0) t0 = t0 * t0 + f[0];
  if (compute_iterations % 8 > 1) t1 = t1 * t1 + f[1];
  if (compute_iterations % 8 > 2) t2 = t2 * t2 + f[2];
  if (compute_iterations % 8 > 3) t3 = t3 * t3 + f[3];
  if (compute_iterations % 8 > 4) t4 = t4 * t4 + f[4];
  if (compute_iterations % 8 > 5) t5 = t5 * t5 + f[5];
  if (compute_iterations % 8 > 6) t6 = t6 * t6 + f[6];

  return t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
}

template <typename T, unsigned int compute_iterations>
__global__ void bench_chunks_kernel(const T* src, T* partial, size_t num_chunks) {
  size_t chunk = blockIdx.x;
  if (chunk >= num_chunks) return;

  size_t base = chunk * STATIC_CHUNK_SIZE;

  T f[8];
#pragma unroll
  for (int i = 0; i < 8; i++) f[i] = src[base + i];

  T local_sum = (T)0;
  for (size_t i = threadIdx.x; i < STATIC_CHUNK_SIZE; i += blockDim.x) {
    T v = src[base + i];
    local_sum += bench_elem<T, compute_iterations>(v, f);
  }

  extern __shared__ unsigned char smem_raw[];
  T* smem = reinterpret_cast<T*>(smem_raw);
  smem[threadIdx.x] = local_sum;
  __syncthreads();

  for (unsigned int s = blockDim.x >> 1; s > 0; s >>= 1) {
    if (threadIdx.x < s) smem[threadIdx.x] += smem[threadIdx.x + s];
    __syncthreads();
  }

  if (threadIdx.x == 0) partial[chunk] = smem[0];
}

template <typename T>
__global__ void reduce_sum_kernel(const T* in, T* out, size_t n) {
  extern __shared__ unsigned char smem_raw[];
  T* smem = reinterpret_cast<T*>(smem_raw);

  size_t tid = threadIdx.x;
  size_t i = blockIdx.x * (blockDim.x * 2) + tid;

  T sum = (T)0;
  if (i < n) sum = in[i];
  if (i + blockDim.x < n) sum += in[i + blockDim.x];

  smem[tid] = sum;
  __syncthreads();

  for (unsigned int s = blockDim.x >> 1; s > 0; s >>= 1) {
    if (tid < s) smem[tid] += smem[tid + s];
    __syncthreads();
  }

  if (tid == 0) out[blockIdx.x] = smem[0];
}

template <typename T>
__global__ void copy_first_kernel(T* dst, const T* src) {
  if (threadIdx.x == 0 && blockIdx.x == 0) dst[0] = src[0];
}

template <typename Element, unsigned int compute_iterations>
size_t bench_cuda(size_t len, Element* src, Element* ws1, Element* ws2) {
  const size_t num_chunks = len / STATIC_CHUNK_SIZE;
  if (num_chunks == 0) {
    return len;
  }

  bench_chunks_kernel<Element, compute_iterations>
      <<<static_cast<unsigned int>(num_chunks), BENCH_BLOCK_THREADS,
         BENCH_BLOCK_THREADS * sizeof(Element)>>>(src, ws1, num_chunks);

  Element* in = ws1;
  Element* out = ws2;
  size_t n = num_chunks;

  while (n > 1) {
    size_t blocks = (n + BENCH_BLOCK_THREADS * 2 - 1) / (BENCH_BLOCK_THREADS * 2);
    reduce_sum_kernel<Element><<<static_cast<unsigned int>(blocks), BENCH_BLOCK_THREADS,
                                 BENCH_BLOCK_THREADS * sizeof(Element)>>>(in, out, n);
    n = blocks;
    Element* tmp = in;
    in = out;
    out = tmp;
  }

  copy_first_kernel<Element><<<1, 1>>>(src, in);
  return len;
}

template <typename Op>
double measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  cudaDeviceSynchronize();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() /
         1000.0;
}

template <typename Op>
double benchmark_cuda(Op op, bool half_phase) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();
  std::vector<double> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (half_phase) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

auto runbench_warmup(void* dmem, size_t size_bytes) {
  const size_t num_elements = size_bytes / sizeof(double);
  const size_t num_chunks = num_elements / STATIC_CHUNK_SIZE;
  auto timer_start = benchmark_clock::now();

  double* dptr = reinterpret_cast<double*>(dmem);
  double *ws1 = nullptr, *ws2 = nullptr;
  cudaMalloc(&ws1, num_chunks * sizeof(double));
  cudaMalloc(&ws2, num_chunks * sizeof(double));

  bench_cuda<double, 16>(num_elements, dptr, ws1, ws2);
  cudaDeviceSynchronize();

  cudaFree(ws1);
  cudaFree(ws2);

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <unsigned int compute_iterations>
void runbench(void* dmem, size_t size_bytes, bool half_phase) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(dmem);
  size_t float_chunks = cs.element_count<float>() / STATIC_CHUNK_SIZE;
  float *fws1 = nullptr, *fws2 = nullptr;
  cudaMalloc(&fws1, float_chunks * sizeof(float));
  cudaMalloc(&fws2, float_chunks * sizeof(float));

  auto kernel_time_mad_sp = benchmark_cuda(
      [&] {
        return measure_operation([&] {
          bench_cuda<float, compute_iterations>(cs.element_count<float>(), c_as_float, fws1,
                                                fws2);
        });
      },
      half_phase);

  double* c_as_double = reinterpret_cast<double*>(dmem);
  size_t double_chunks = cs.element_count<double>() / STATIC_CHUNK_SIZE;
  double *dws1 = nullptr, *dws2 = nullptr;
  cudaMalloc(&dws1, double_chunks * sizeof(double));
  cudaMalloc(&dws2, double_chunks * sizeof(double));

  auto kernel_time_mad_dp = benchmark_cuda(
      [&] {
        return measure_operation([&] {
          bench_cuda<double, compute_iterations>(cs.element_count<double>(), c_as_double, dws1,
                                                 dws2);
        });
      },
      half_phase);

  int* c_as_int = reinterpret_cast<int*>(dmem);
  size_t int_chunks = cs.element_count<int>() / STATIC_CHUNK_SIZE;
  int *iws1 = nullptr, *iws2 = nullptr;
  cudaMalloc(&iws1, int_chunks * sizeof(int));
  cudaMalloc(&iws2, int_chunks * sizeof(int));

  auto kernel_time_mad_int = benchmark_cuda(
      [&] {
        return measure_operation([&] {
          bench_cuda<int, compute_iterations>(cs.element_count<int>(), c_as_int, iws1, iws2);
        });
      },
      half_phase);

  cudaFree(fws1);
  cudaFree(fws2);
  cudaFree(dws1);
  cudaFree(dws2);
  cudaFree(iws1);
  cudaFree(iws2);

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations << ",   "
            << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) / static_cast<double>(memory_traffic) << ","
            << setw(8) << setprecision(2) << kernel_time_mad_sp << "," << setw(8)
            << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) / static_cast<double>(memory_traffic) << ","
            << setw(8) << setprecision(2) << kernel_time_mad_dp << "," << setw(8)
            << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) / static_cast<double>(memory_traffic) << ","
            << setw(8) << setprecision(2) << kernel_time_mad_int << "," << setw(8)
            << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int * 1000. /
                   (1000. * 1000. * 1000.)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* dmem, size_t size_bytes, bool half_phase) {
  runbench<compute_iterations>(dmem, size_bytes, half_phase);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* dmem, size_t size_bytes, bool half_phase) {
  runbench_range<j1>(dmem, size_bytes, half_phase);
  runbench_range<j2, Args...>(dmem, size_bytes, half_phase);
}

extern "C" void mixbenchGPU(double* c, long size) {
  (void)c;

  size_t size_bytes = static_cast<size_t>(size) * sizeof(double);

  void* dmem = nullptr;
  cudaMalloc(&dmem, size_bytes);

  size_t int_count = size_bytes / sizeof(int);
  size_t blocks = (int_count + 255) / 256;
  zero_kernel<int><<<static_cast<unsigned int>(blocks), 256>>>(reinterpret_cast<int*>(dmem),
                                                                int_count);
  cudaDeviceSynchronize();

  cudaDeviceProp prop{};
  int device = 0;
  cudaGetDevice(&device);
  cudaGetDeviceProperties(&prop, device);
  bool half_phase = prop.multiProcessorCount > 1;

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(dmem, size_bytes);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(dmem, size_bytes, half_phase);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  cudaFree(dmem);
}
